// --- Agent G: Compliance Agent — Jurisdiction-Aware Regulatory Governance ---
app.get('/compliance', async (req, res) => {
  const nexusName = process.env.NEXUS_NAME || 'AIRS Nexus';
  const entityLabel = process.env.ENTITY_LABEL || 'Record';
  const fields = (process.env.FIELD_LABELS || '').split('|').filter(Boolean);
  const agentStart = Date.now();
  
  // Zero-token deterministic compliance lookup
  var domainSignals = (nexusName + ' ' + entityLabel + ' ' + fields.join(' ')).toLowerCase();
  var frameworks = [];
  
  // Education
  if (/student|teacher|educator|school|iep|classroom|pld|curriculum|tutor|instruction/.test(domainSignals)) {
    frameworks.push({name:'FERPA',full:'Family Educational Rights and Privacy Act',applies:'Student records, directory information, parental consent',status:'REQUIRED',color:'#2563EB'});
    frameworks.push({name:'IDEA',full:'Individuals with Disabilities Education Act',applies:'IEP documentation, special education services, disability accommodations',status:'REQUIRED',color:'#2563EB'});
    frameworks.push({name:'Section 504',full:'Rehabilitation Act Section 504',applies:'Disability accommodation plans, non-discrimination',status:'REQUIRED',color:'#2563EB'});
    frameworks.push({name:'Title IX',full:'Title IX of the Education Amendments',applies:'Gender equity, discrimination prevention',status:'REVIEW',color:'#D97706'});
  }
  // Healthcare
  if (/patient|medical|health|clinical|diagnosis|treatment|biomarker|hospital|physician|nurse|pharmacy/.test(domainSignals)) {
    frameworks.push({name:'HIPAA',full:'Health Insurance Portability and Accountability Act',applies:'Protected health information, data transmission, breach notification',status:'REQUIRED',color:'#DC2626'});
    frameworks.push({name:'HITECH',full:'Health Information Technology for Economic and Clinical Health Act',applies:'Electronic health records, meaningful use, breach penalties',status:'REQUIRED',color:'#DC2626'});
    frameworks.push({name:'FDA SaMD',full:'FDA Software as a Medical Device Guidance',applies:'AI/ML-based clinical decision support, diagnostic tools',status:'REVIEW',color:'#D97706'});
    frameworks.push({name:'42 CFR Part 2',full:'Confidentiality of Substance Use Disorder Records',applies:'Substance use treatment records, consent requirements',status:'CONDITIONAL',color:'#D97706'});
  }
  // Veterans / Justice
  if (/veteran|military|court|justice|probation|parole|hearing|mentor|service.member|va /.test(domainSignals)) {
    frameworks.push({name:'VOCA',full:'Victims of Crime Act',applies:'Victim services funding, reporting requirements',status:'REVIEW',color:'#D97706'});
    frameworks.push({name:'PREA',full:'Prison Rape Elimination Act',applies:'Incarceration conditions, reporting mandates',status:'CONDITIONAL',color:'#D97706'});
    frameworks.push({name:'38 USC',full:'Title 38 United States Code',applies:'Veterans benefits, VA data sharing, service-connected claims',status:'REQUIRED',color:'#2563EB'});
    frameworks.push({name:'CJIS',full:'Criminal Justice Information Services Policy',applies:'Criminal records access, background checks, data security',status:'REQUIRED',color:'#DC2626'});
  }
  // Child Welfare
  if (/child|minor|foster|placement|abuse|neglect|family|sibling|reunification|adoption|capta/.test(domainSignals)) {
    frameworks.push({name:'CAPTA',full:'Child Abuse Prevention and Treatment Act',applies:'Mandatory reporting, investigation protocols',status:'REQUIRED',color:'#DC2626'});
    frameworks.push({name:'ASFA',full:'Adoption and Safe Families Act',applies:'Permanency timelines, reunification requirements',status:'REQUIRED',color:'#2563EB'});
    frameworks.push({name:'ICWA',full:'Indian Child Welfare Act',applies:'Tribal jurisdiction, placement preferences',status:'CONDITIONAL',color:'#D97706'});
    frameworks.push({name:'Title IV-E',full:'Social Security Act Title IV-E',applies:'Foster care funding, eligibility documentation',status:'REQUIRED',color:'#2563EB'});
  }
  // International / UN
  if (/refugee|asylum|migration|un |united.nations|sdg|humanitarian|displacement|embassy|belize|international/.test(domainSignals)) {
    frameworks.push({name:'GDPR',full:'General Data Protection Regulation',applies:'EU/EEA personal data, consent, right to erasure, data portability',status:'REVIEW',color:'#D97706'});
    frameworks.push({name:'UN Data Governance',full:'UN Secretary-General Data Strategy',applies:'Data sovereignty, cross-agency sharing, population data ethics',status:'REQUIRED',color:'#2563EB'});
    frameworks.push({name:'Convention on Rights of the Child',full:'CRC — UN Treaty',applies:'Minor data protection, best interest principle',status:'REQUIRED',color:'#DC2626'});
  }
  // Finance
  if (/financial|banking|loan|credit|insurance|claim|audit|revenue|billing|reimbursement/.test(domainSignals)) {
    frameworks.push({name:'SOX',full:'Sarbanes-Oxley Act',applies:'Financial reporting, internal controls, audit trails',status:'REQUIRED',color:'#2563EB'});
    frameworks.push({name:'PCI-DSS',full:'Payment Card Industry Data Security Standard',applies:'Cardholder data, encryption, access controls',status:'CONDITIONAL',color:'#D97706'});
  }
  // Data Protection (universal)
  frameworks.push({name:'AI Governance',full:'AIRS IGM — Inference Governance Module',applies:'Token budgets, receipted inference, audit trails, governance gates',status:'ACTIVE',color:'#059669'});
  
  // Check each field against compliance
  var fieldChecks = fields.map(function(f, i) {
    var fl = f.toLowerCase();
    var flags = [];
    if (/name|ssn|dob|address|phone|email|identity/.test(fl)) flags.push({flag:'PII FIELD',severity:'HIGH',action:'Requires encryption at rest and masking in display',color:'#DC2626'});
    if (/diagnosis|treatment|medication|health|medical|disability/.test(fl)) flags.push({flag:'PHI FIELD',severity:'CRITICAL',action:'HIPAA Safe Harbor or Expert Determination required before sharing',color:'#DC2626'});
    if (/iep|504|disability|special.ed|accommodation/.test(fl)) flags.push({flag:'IDEA PROTECTED',severity:'HIGH',action:'Parental consent required, annual review mandated',color:'#2563EB'});
    if (/income|poverty|housing|homeless/.test(fl)) flags.push({flag:'SENSITIVE',severity:'MEDIUM',action:'Limit access to authorized personnel, audit all views',color:'#D97706'});
    if (/score|risk|predict|probability|forecast/.test(fl)) flags.push({flag:'AI OUTPUT',severity:'HIGH',action:'Must include confidence bounds, human approval required before action',color:'#7C3AED'});
    if (flags.length === 0) flags.push({flag:'STANDARD',severity:'LOW',action:'Standard governance — audit trail active',color:'#059669'});
    return {field: f, index: i+1, flags: flags};
  });

  var duration = Date.now() - agentStart;
  
  // Render
  var frameworkRows = frameworks.map(function(fw) {
    var statusColor = fw.status === 'REQUIRED' ? '#DC2626' : fw.status === 'ACTIVE' ? '#059669' : '#D97706';
    return '<tr><td style="padding:10px;border-bottom:1px solid #E2E8F0"><span style="font-size:12px;font-weight:700;color:' + fw.color + '">' + fw.name + '</span></td>' +
      '<td style="padding:10px;border-bottom:1px solid #E2E8F0;font-size:12px;color:#0F172A">' + fw.full + '</td>' +
      '<td style="padding:10px;border-bottom:1px solid #E2E8F0;font-size:12px;color:#475569">' + fw.applies + '</td>' +
      '<td style="padding:10px;border-bottom:1px solid #E2E8F0"><span style="font-size:10px;font-weight:700;padding:2px 8px;border-radius:4px;background:' + statusColor + ';color:#fff">' + fw.status + '</span></td></tr>';
  }).join('');
  
  var fieldRows = fieldChecks.map(function(fc) {
    var flagBadges = fc.flags.map(function(fl) {
      return '<span style="display:inline-block;font-size:10px;font-weight:700;padding:2px 8px;border-radius:4px;margin-right:4px;margin-bottom:4px;background:' + fl.color + ';color:#fff">' + fl.flag + '</span>';
    }).join('');
    var actions = fc.flags.map(function(fl) { return fl.action; }).join('. ');
    return '<tr><td style="padding:10px;border-bottom:1px solid #E2E8F0;font-size:12px;font-weight:600">' + fc.index + '</td>' +
      '<td style="padding:10px;border-bottom:1px solid #E2E8F0;font-size:13px;font-weight:600;color:#0F172A">' + fc.field + '</td>' +
      '<td style="padding:10px;border-bottom:1px solid #E2E8F0">' + flagBadges + '</td>' +
      '<td style="padding:10px;border-bottom:1px solid #E2E8F0;font-size:12px;color:#475569">' + actions + '</td></tr>';
  }).join('');

  var highFlags = fieldChecks.reduce(function(sum, fc) { return sum + fc.flags.filter(function(f){return f.severity==='HIGH'||f.severity==='CRITICAL'}).length; }, 0);

  res.send('<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1">' +
    '<title>' + nexusName + ' — Compliance Report</title>' +
    '<style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:Inter,system-ui,sans-serif;color:#0F172A;background:#fff}' +
    'h2{font-size:18px;font-weight:700;margin-bottom:16px;margin-top:32px;padding-bottom:8px;border-bottom:2px solid #E2E8F0}' +
    'table{width:100%;border-collapse:collapse;margin-bottom:24px}' +
    'th{text-align:left;padding:10px;font-size:10px;font-weight:700;letter-spacing:.06em;text-transform:uppercase;color:#475569;border-bottom:2px solid #E2E8F0}' +
    '@media print{.header{-webkit-print-color-adjust:exact;print-color-adjust:exact}.no-print{display:none}}</style></head><body>' +
    
    '<div class="header" style="background:linear-gradient(135deg,#0F172A,#1E293B);padding:40px 48px;color:#fff">' +
    '<div style="font-size:9px;font-weight:700;letter-spacing:.16em;color:rgba(255,255,255,.4);text-transform:uppercase;margin-bottom:8px">Agent G: Compliance Agent \u00b7 Zero-Token Regulatory Scan \u00b7 ' + new Date().toISOString().split('T')[0] + '</div>' +
    '<div style="font-size:32px;font-weight:800;margin-bottom:6px">' + nexusName + ' — Compliance Audit</div>' +
    '<div style="font-size:14px;color:rgba(255,255,255,.6)">Entity: ' + entityLabel + ' | Frameworks detected: ' + frameworks.length + ' | Field flags: ' + highFlags + ' HIGH/CRITICAL</div>' +
    '<div style="display:flex;gap:16px;margin-top:16px">' +
    '<div style="text-align:center"><div style="font-size:24px;font-weight:800;color:#60A5FA">' + frameworks.length + '</div><div style="font-size:10px;color:rgba(255,255,255,.5)">Frameworks</div></div>' +
    '<div style="text-align:center"><div style="font-size:24px;font-weight:800;color:#DC2626">' + highFlags + '</div><div style="font-size:10px;color:rgba(255,255,255,.5)">High/Critical Flags</div></div>' +
    '<div style="text-align:center"><div style="font-size:24px;font-weight:800;color:#34D399">0</div><div style="font-size:10px;color:rgba(255,255,255,.5)">Tokens Used</div></div>' +
    '<div style="text-align:center"><div style="font-size:24px;font-weight:800;color:#FBBF24">' + duration + 'ms</div><div style="font-size:10px;color:rgba(255,255,255,.5)">Scan Duration</div></div>' +
    '</div></div>' +
    
    '<div style="max-width:900px;margin:0 auto;padding:40px 48px">' +
    '<div class="no-print" style="background:#DBEAFE;padding:12px 16px;border-radius:8px;margin-bottom:24px;font-size:13px;color:#1E40AF"><strong>To save as PDF:</strong> Press Cmd+P (Mac) or Ctrl+P (Windows)</div>' +
    
    '<h2>Applicable Regulatory Frameworks</h2>' +
    '<table><thead><tr><th>Framework</th><th>Full Name</th><th>Applies To</th><th>Status</th></tr></thead><tbody>' + frameworkRows + '</tbody></table>' +
    
    '<h2>Field-Level Compliance Scan</h2>' +
    '<table><thead><tr><th>#</th><th>Field</th><th>Flags</th><th>Required Action</th></tr></thead><tbody>' + fieldRows + '</tbody></table>' +
    
    '<h2>Agent G Governance Receipt</h2>' +
    '<div style="background:#F8FAFC;border:1px solid #E2E8F0;border-radius:10px;padding:20px;font-family:monospace;font-size:12px;color:#475569;line-height:1.8">' +
    'Agent: G (Compliance Agent)<br>' +
    'Type: DETERMINISTIC — Zero AI tokens<br>' +
    'Frameworks scanned: ' + frameworks.length + '<br>' +
    'Fields audited: ' + fields.length + '<br>' +
    'High/Critical flags: ' + highFlags + '<br>' +
    'Duration: ' + duration + 'ms<br>' +
    'Method: Pattern-matching regulatory lookup (no LLM inference)<br>' +
    'This scan is deterministic and reproducible. Same input always produces same output.<br>' +
    'USPTO Patent Pending 19/571,156 \u00b7 DeBacco Nexus LLC' +
    '</div>' +
    
    '</div>' +
    '<div style="border-top:2px solid #E2E8F0;padding:24px 48px;font-size:11px;color:#475569;text-align:center">AIRS \u2014 AI Insight | See what your system can\u2019t | Agent G: Zero-Token Compliance | DeBacco Nexus LLC</div>' +
    '</body></html>');
});


